 constraints","ARCHITECTURE.md must be updated to include the new domain entities: Employee, LeavePolicy, LeaveBalance, LeaveRequest, Notification and their repository interfaces"],"sqlSchema":"CREATE TABLE employees (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_number VARCHAR(50) UNIQUE NOT NULL,
  first_name VARCHAR(100) NOT NULL,
  last_name VARCHAR(100) NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  manager_id UUID REFERENCES employees(id),
  department VARCHAR(100),
  hire_date DATE NOT NULL,
  employment_status VARCHAR(50) NOT NULL CHECK (employment_status IN ('active', 'inactive', 'terminated')),
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE leave_policies (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  policy_name VARCHAR(100) UNIQUE NOT NULL,
  leave_type VARCHAR(50) NOT NULL CHECK (leave_type IN ('annual', 'sick', 'emergency', 'unpaid', 'maternity', 'paternity')),
  entitlement_days INTEGER NOT NULL CHECK (entitlement_days >= 0),
  accrual_rate DECIMAL(5,2) DEFAULT 0.0,
  max_carryover INTEGER DEFAULT 0,
  requires_approval BOOLEAN DEFAULT true,
  min_service_days INTEGER DEFAULT 0,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE leave_balances (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_id UUID NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  policy_id UUID NOT NULL REFERENCES leave_policies(id),
  fiscal_year INTEGER NOT NULL,
  accrued_days DECIMAL(5,2) DEFAULT 0.0,
  used_days DECIMAL(5,2) DEFAULT 0.0,
  carried_over DECIMAL(5,2) DEFAULT 0.0,
  balance_days DECIMAL(5,2) GENERATED ALWAYS AS (accrued_days + carried_over - used_days) STORED,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(employee_id, policy_id, fiscal_year)
);

CREATE TABLE leave_requests (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_id UUID NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  policy_id UUID NOT NULL REFERENCES leave_policies(id),
  start_date DATE NOT NULL,
  end_date DATE NOT NULL,
  total_days DECIMAL(5,2) NOT NULL CHECK (total_days > 0),
  status VARCHAR(50) NOT NULL DEFAULT 'pending' CHECK (status IN ('draft', 'submitted', 'pending_approval', 'approved', 'rejected', 'cancelled')),
  reason TEXT,
  manager_id UUID REFERENCES employees(id),
  reviewed_at TIMESTAMP WITH TIME ZONE,
  review_notes TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  CHECK (end_date >= start_date)
);

CREATE TABLE notifications (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  recipient_id UUID NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  sender_id UUID REFERENCES employees(id),
  type VARCHAR(50) NOT NULL CHECK (type IN ('leave_submitted', 'leave_approved', 'leave_rejected', 'balance_low', 'system_alert')),
  title VARCHAR(200) NOT NULL,
  message TEXT NOT NULL,
  metadata JSONB,
  is_read BOOLEAN DEFAULT false,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
  read_at TIMESTAMP WITH TIME ZONE
);"}

